import React, { useState, useEffect, useCallback } from 'react';
import { getMe, getStocks, createStock, updatePrice, buyStock, sellStock } from '../api';
import { useWebSocket } from '../useWebSocket';

export default function Dashboard({ onLogout }) {
  const [user, setUser] = useState(null);
  const [stocks, setStocks] = useState([]); // live prices stored here
  const [myStock, setMyStock] = useState(null);

  // Forms
  const [newTicker, setNewTicker] = useState('');
  const [newName, setNewName] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newPriceInput, setNewPriceInput] = useState('');
  const [tradeShares, setTradeShares] = useState({});
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);

  // Load initial data
  useEffect(() => {
    async function load() {
      const [userData, stocksData] = await Promise.all([getMe(), getStocks()]);
      setUser(userData);
      setStocks(stocksData);
      // Find user's own stock
      const mine = stocksData.find(s => s.ownerUsername === userData.username);
      setMyStock(mine || null);
    }
    load();
  }, []);

  // ── WebSocket: update prices in real-time ──────────────────────
  const handleWsMessage = useCallback((data) => {
    if (data.type === 'TICKER_UPDATE') {
      const { ticker, price } = data.payload;
      setStocks(prev =>
        prev.map(s => s.ticker === ticker ? { ...s, price } : s)
      );
    }
  }, []);

  useWebSocket(handleWsMessage);

  // ── Calculated Net Worth (NEVER stored in DB) ──────────────────
  // Valuation = walletBalance + sum(shares × currentPrice)
  function calcNetWorth() {
    if (!user) return 0;
    const portfolioValue = (user.portfolio || []).reduce((acc, holding) => {
      const stock = stocks.find(s => s.ticker === holding.ticker);
      const price = stock ? stock.price : 0;
      return acc + holding.shares * price;
    }, 0);
    return user.walletBalance + portfolioValue;
  }

  function flash(text) {
    setMsg(text);
    setTimeout(() => setMsg(''), 3000);
  }

  // ── Create stock ───────────────────────────────────────────────
  async function handleCreateStock(e) {
    e.preventDefault();
    setLoading(true);
    const data = await createStock(newTicker, newName, parseFloat(newPrice));
    setLoading(false);
    if (data._id) {
      setStocks(prev => [data, ...prev]);
      setMyStock(data);
      setNewTicker(''); setNewName(''); setNewPrice('');
      flash('✅ Stock created!');
    } else {
      flash('❌ ' + (data.message || 'Error'));
    }
  }

  // ── Update price ───────────────────────────────────────────────
  async function handleUpdatePrice(e) {
    e.preventDefault();
    if (!myStock) return;
    setLoading(true);
    const data = await updatePrice(myStock.ticker, parseFloat(newPriceInput));
    setLoading(false);
    if (data._id) {
      setMyStock(data);
      setNewPriceInput('');
      flash(`✅ Price updated → $${data.price}`);
      // WebSocket will propagate to all other clients
    } else {
      flash('❌ ' + (data.message || 'Error'));
    }
  }

  // ── Buy ────────────────────────────────────────────────────────
  async function handleBuy(ticker) {
    const shares = parseInt(tradeShares[ticker] || 1);
    setLoading(true);
    const data = await buyStock(ticker, shares);
    setLoading(false);
    if (data.walletBalance !== undefined) {
      setUser(prev => ({ ...prev, walletBalance: data.walletBalance, portfolio: data.portfolio }));
      flash(`✅ Bought ${shares} share(s) of $${ticker}`);
    } else {
      flash('❌ ' + (data.message || 'Error'));
    }
  }

  // ── Sell ───────────────────────────────────────────────────────
  async function handleSell(ticker) {
    const shares = parseInt(tradeShares[ticker] || 1);
    setLoading(true);
    const data = await sellStock(ticker, shares);
    setLoading(false);
    if (data.walletBalance !== undefined) {
      setUser(prev => ({ ...prev, walletBalance: data.walletBalance, portfolio: data.portfolio }));
      flash(`✅ Sold ${shares} share(s) of $${ticker}`);
    } else {
      flash('❌ ' + (data.message || 'Error'));
    }
  }

  function getHolding(ticker) {
    if (!user) return 0;
    const h = (user.portfolio || []).find(p => p.ticker === ticker);
    return h ? h.shares : 0;
  }

  if (!user) return <div style={styles.loading}>Loading PEX...</div>;

  const netWorth = calcNetWorth();

  return (
    <div style={styles.page}>
      {/* ── Header ── */}
      <div style={styles.header}>
        <span style={styles.headerLogo}>💹 PEX</span>
        <span style={styles.headerUser}>@{user.username}</span>
        <button style={styles.logoutBtn} onClick={onLogout}>Logout</button>
      </div>

      {/* ── Flash message ── */}
      {msg && <div style={styles.flash}>{msg}</div>}

      {/* ── Stats row ── */}
      <div style={styles.statsRow}>
        <StatCard label="Wallet Balance" value={`$${user.walletBalance.toFixed(2)}`} color="#00d4aa" />
        <StatCard label="Net Worth (live)" value={`$${netWorth.toFixed(2)}`} color="#7c6bf0" />
        <StatCard label="Stocks in Market" value={stocks.length} color="#f0a06b" />
      </div>

      <div style={styles.grid}>
        {/* ── Left: My Stock ── */}
        <div style={styles.panel}>
          <h3 style={styles.panelTitle}>My Stock</h3>
          {!myStock ? (
            <form onSubmit={handleCreateStock}>
              <p style={styles.hint}>Issue your company stock on PEX</p>
              <input style={styles.input} placeholder="Ticker (e.g. DEV)" value={newTicker} onChange={e => setNewTicker(e.target.value.toUpperCase())} maxLength={5} required />
              <input style={styles.input} placeholder="Company Name" value={newName} onChange={e => setNewName(e.target.value)} required />
              <input style={styles.input} placeholder="Initial Price ($)" type="number" min="0.01" step="0.01" value={newPrice} onChange={e => setNewPrice(e.target.value)} required />
              <button style={styles.btnGreen} disabled={loading}>Issue Stock</button>
            </form>
          ) : (
            <div>
              <div style={styles.stockCard}>
                <div style={styles.tickerBadge}>${myStock.ticker}</div>
                <div style={styles.stockName}>{myStock.name}</div>
                <div style={styles.stockPrice}>${myStock.price.toFixed(2)}</div>
              </div>
              <form onSubmit={handleUpdatePrice} style={{ marginTop: 16 }}>
                <label style={styles.label}>Update Price</label>
                <input style={styles.input} placeholder="New price ($)" type="number" min="0.01" step="0.01" value={newPriceInput} onChange={e => setNewPriceInput(e.target.value)} required />
                <button style={styles.btnBlue} disabled={loading}>Broadcast New Price</button>
              </form>
            </div>
          )}

          {/* ── Portfolio ── */}
          <h3 style={{ ...styles.panelTitle, marginTop: 32 }}>My Portfolio</h3>
          {(user.portfolio || []).length === 0 ? (
            <p style={styles.hint}>No holdings yet. Buy from the market!</p>
          ) : (
            (user.portfolio || []).map(h => {
              const s = stocks.find(st => st.ticker === h.ticker);
              const val = s ? s.price * h.shares : 0;
              return (
                <div key={h.ticker} style={styles.holdingRow}>
                  <span style={styles.holdingTicker}>${h.ticker}</span>
                  <span style={styles.holdingShares}>{h.shares} shares</span>
                  <span style={styles.holdingVal}>${val.toFixed(2)}</span>
                </div>
              );
            })
          )}
        </div>

        {/* ── Right: Market ── */}
        <div style={styles.panel}>
          <h3 style={styles.panelTitle}>Live Market</h3>
          {stocks.length === 0 && <p style={styles.hint}>No stocks listed yet.</p>}
          {stocks.map(stock => (
            <div key={stock.ticker} style={styles.marketRow}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <span style={styles.tickerBadgeSmall}>${stock.ticker}</span>
                  <span style={styles.stockOwner}>by @{stock.ownerUsername}</span>
                </div>
                <span style={styles.livePrice}>${stock.price.toFixed(2)}</span>
              </div>
              <div style={{ fontSize: 12, color: '#555', marginTop: 2 }}>{stock.name}</div>

              {/* Don't show trade controls on your own stock */}
              {stock.ownerUsername !== user.username && (
                <div style={styles.tradeRow}>
                  <input
                    style={styles.sharesInput}
                    type="number"
                    min="1"
                    placeholder="Shares"
                    value={tradeShares[stock.ticker] || ''}
                    onChange={e => setTradeShares(prev => ({ ...prev, [stock.ticker]: e.target.value }))}
                  />
                  <button style={styles.btnBuySmall} onClick={() => handleBuy(stock.ticker)} disabled={loading}>Buy</button>
                  {getHolding(stock.ticker) > 0 && (
                    <button style={styles.btnSellSmall} onClick={() => handleSell(stock.ticker)} disabled={loading}>Sell</button>
                  )}
                  {getHolding(stock.ticker) > 0 && (
                    <span style={styles.holdingBadge}>You own: {getHolding(stock.ticker)}</span>
                  )}
                </div>
              )}
              {stock.ownerUsername === user.username && (
                <div style={{ fontSize: 12, color: '#00d4aa', marginTop: 6 }}>← Your stock</div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function StatCard({ label, value, color }) {
  return (
    <div style={{ background: '#13131a', border: `1px solid ${color}33`, borderRadius: 12, padding: '18px 24px', flex: 1, minWidth: 140 }}>
      <div style={{ color: '#777', fontSize: 12, marginBottom: 6 }}>{label}</div>
      <div style={{ color, fontSize: 24, fontWeight: 700 }}>{value}</div>
    </div>
  );
}

const styles = {
  page: { minHeight: '100vh', background: '#0a0a0f', color: '#fff', fontFamily: 'system-ui, sans-serif', paddingBottom: 40 },
  loading: { color: '#fff', textAlign: 'center', paddingTop: 80, fontSize: 20, background: '#0a0a0f', minHeight: '100vh' },
  header: { display: 'flex', alignItems: 'center', gap: 16, padding: '16px 24px', borderBottom: '1px solid #1e1e2e', background: '#0d0d14' },
  headerLogo: { fontSize: 22, fontWeight: 700 },
  headerUser: { color: '#00d4aa', fontWeight: 600 },
  logoutBtn: { marginLeft: 'auto', background: 'transparent', border: '1px solid #333', color: '#888', borderRadius: 8, padding: '6px 14px', cursor: 'pointer' },
  flash: { margin: '12px 24px 0', padding: '10px 16px', background: '#1a1a24', borderRadius: 8, color: '#00d4aa', fontSize: 14 },
  statsRow: { display: 'flex', gap: 16, padding: '20px 24px', flexWrap: 'wrap' },
  grid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20, padding: '0 24px' },
  panel: { background: '#13131a', border: '1px solid #1e1e2e', borderRadius: 16, padding: 24 },
  panelTitle: { color: '#fff', margin: '0 0 16px', fontSize: 16, fontWeight: 600 },
  hint: { color: '#555', fontSize: 13 },
  input: {
    width: '100%', padding: '10px 12px', marginBottom: 10, borderRadius: 8,
    border: '1px solid #2a2a3a', background: '#1a1a24', color: '#fff',
    fontSize: 14, boxSizing: 'border-box', outline: 'none',
  },
  label: { color: '#888', fontSize: 12, display: 'block', marginBottom: 6 },
  btnGreen: { width: '100%', padding: '11px', borderRadius: 8, border: 'none', background: 'linear-gradient(135deg,#00d4aa,#00a896)', color: '#000', fontWeight: 700, cursor: 'pointer' },
  btnBlue: { width: '100%', padding: '11px', borderRadius: 8, border: 'none', background: 'linear-gradient(135deg,#7c6bf0,#5b4ecc)', color: '#fff', fontWeight: 700, cursor: 'pointer' },
  stockCard: { background: '#1a1a24', borderRadius: 10, padding: 16 },
  tickerBadge: { background: '#00d4aa22', color: '#00d4aa', padding: '4px 10px', borderRadius: 6, fontWeight: 700, fontSize: 18, display: 'inline-block', marginBottom: 8 },
  stockName: { color: '#ccc', fontSize: 13, marginBottom: 8 },
  stockPrice: { color: '#fff', fontSize: 28, fontWeight: 700 },
  holdingRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 0', borderBottom: '1px solid #1e1e2e' },
  holdingTicker: { color: '#00d4aa', fontWeight: 700, fontSize: 14 },
  holdingShares: { color: '#888', fontSize: 13 },
  holdingVal: { color: '#fff', fontWeight: 600, fontSize: 14 },
  marketRow: { background: '#1a1a24', borderRadius: 10, padding: 14, marginBottom: 10 },
  tickerBadgeSmall: { background: '#00d4aa22', color: '#00d4aa', padding: '2px 8px', borderRadius: 5, fontWeight: 700, fontSize: 13, marginRight: 8 },
  stockOwner: { color: '#555', fontSize: 12 },
  livePrice: { color: '#fff', fontWeight: 700, fontSize: 18 },
  tradeRow: { display: 'flex', gap: 6, alignItems: 'center', marginTop: 10, flexWrap: 'wrap' },
  sharesInput: { width: 70, padding: '6px 8px', borderRadius: 6, border: '1px solid #2a2a3a', background: '#0a0a0f', color: '#fff', fontSize: 13, outline: 'none' },
  btnBuySmall: { padding: '6px 12px', borderRadius: 6, border: 'none', background: '#00d4aa', color: '#000', fontWeight: 700, fontSize: 12, cursor: 'pointer' },
  btnSellSmall: { padding: '6px 12px', borderRadius: 6, border: 'none', background: '#ff6b6b', color: '#fff', fontWeight: 700, fontSize: 12, cursor: 'pointer' },
  holdingBadge: { color: '#888', fontSize: 12 },
};
